import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
export const expandedBatch5: ScenarioQuestion[] = [
  q("sq-ex5-1","interview_preparation","behavioral","You worked as a CNA before nursing school.","How has your CNA experience shaped your nursing practice?","Working as a CNA taught me the importance of basic patient care, communication with nursing staff, and time management. I understand the CNA perspective, which makes me a better delegator and team member. I know what it feels like to be on both sides of delegation, and I bring that empathy to every interaction.","Real-world experience connecting prior roles to nursing practice.","beginner"),
  q("sq-ex5-2","interview_preparation","behavioral","You had to balance school, work, and family responsibilities.","How do you manage competing life demands?","I developed strong organizational skills during nursing school—using planners, setting priorities, and communicating needs with my family and employer. I learned to say no to non-essential commitments and focus on what mattered most. These skills directly translate to managing a busy patient assignment efficiently.","Time management skills developed through life experience.","beginner"),
  q("sq-ex5-3","interview_preparation","behavioral","A patient wrote a complaint about your care that you believe is unjustified.","How would you respond to an unfair complaint?","I would review the complaint objectively and consider whether there is any valid feedback I can learn from. I would discuss it with my manager calmly and provide my perspective with documentation. I would not take it personally but would use it as motivation to ensure my communication and care are consistently excellent.","Objective self-assessment even with perceived unfair feedback.","intermediate"),
  q("sq-ex5-4","interview_preparation","behavioral","You are asked about your experience with death and dying.","How have you handled end-of-life situations?","During my hospice clinical rotation, I provided comfort care for a patient in their final hours. I focused on maintaining dignity, managing symptoms, and supporting the family. After the patient passed, I helped with post-mortem care with reverence and respect. The experience taught me that death is a sacred part of life, and nurses have a privileged role in supporting that transition.","Authentic reflection on end-of-life care experience.","intermediate"),
  q("sq-ex5-5","interview_preparation","behavioral","You are passionate about a specific patient population.","Why are you drawn to this particular patient population?","I am drawn to geriatric patients because of the complexity of their care and the relationships you build over time. My grandmother's hospitalization showed me how important compassionate, patient-centered care is for elderly patients who may feel vulnerable and confused. I want to be the nurse who makes that experience better.","Personal connection driving professional passion.","beginner"),
  q("sq-ex5-6","interview_preparation","clinical_judgment","A patient on a PCA pump is difficult to arouse and has pinpoint pupils.","What do these findings indicate?","Difficult arousal with pinpoint pupils (miosis) in a patient on a PCA pump suggests opioid overdose. I would stop the PCA immediately, stimulate the patient, assess respiratory rate and oxygen saturation, and prepare to administer naloxone (Narcan). I would call for help and monitor for respiratory depression. After reversal, the patient would need close monitoring as naloxone has a shorter half-life than most opioids.","Opioid overdose recognition with immediate reversal preparation.","advanced"),
  q("sq-ex5-7","interview_preparation","clinical_judgment","A diabetic patient develops a fruity breath odor.","What does fruity breath odor indicate in a diabetic?","Fruity or acetone breath odor in a diabetic patient indicates diabetic ketoacidosis. The body is breaking down fats for energy, producing ketones. I would check blood glucose (likely very high), test for ketones, obtain an ABG (likely showing metabolic acidosis), and notify the provider immediately. I would anticipate IV fluids, insulin drip, and electrolyte monitoring.","Classic DKA sign recognition.","beginner"),
  q("sq-ex5-8","interview_preparation","clinical_judgment","A patient receiving a blood transfusion develops flank pain, dark urine, and fever.","What transfusion reaction do you suspect?","Flank pain, dark urine, and fever during a transfusion suggest an acute hemolytic transfusion reaction—the most dangerous type. I would stop the transfusion immediately, maintain IV access with normal saline, send blood and urine samples per protocol, monitor renal function closely, and notify the provider and blood bank immediately. This can lead to DIC and renal failure.","Hemolytic transfusion reaction recognition with emergency response.","advanced"),
  q("sq-ex5-9","interview_preparation","clinical_judgment","A patient with COPD is on 2L nasal cannula and their SpO2 is 88%.","Is this oxygen level acceptable for a COPD patient?","For COPD patients, the target SpO2 is typically 88-92%, as higher levels can suppress their hypoxic drive and reduce respiratory effort. An SpO2 of 88% may be acceptable for this patient. I would assess their baseline, respiratory effort, and level of consciousness. I would not automatically increase oxygen without considering the risk of CO2 retention.","Understanding COPD-specific oxygen targets.","intermediate"),
  q("sq-ex5-10","interview_preparation","clinical_judgment","A patient develops a rigid, board-like abdomen with severe pain.","What does a rigid abdomen suggest?","A rigid, board-like abdomen with severe pain suggests peritonitis—inflammation of the peritoneum, often from a perforated organ. This is a surgical emergency. I would assess vital signs for sepsis indicators, keep the patient NPO, establish IV access, position them comfortably, and notify the surgeon immediately. I would anticipate a CT scan and prepare for possible emergent surgery.","Peritonitis recognition as a surgical emergency.","advanced"),
  q("sq-ex5-11","interview_preparation","clinical_judgment","A patient with pneumonia has a sudden increase in sputum production with purulent, green sputum.","What does a change in sputum character indicate?","A change from scant to copious purulent green sputum suggests worsening infection or a secondary bacterial infection. I would obtain a sputum culture before any antibiotic changes, assess oxygen saturation and respiratory status, auscultate lung sounds, and notify the provider. I would anticipate possible antibiotic adjustment and monitor for sepsis indicators.","Sputum assessment as an infection indicator.","intermediate"),
  q("sq-ex5-12","interview_preparation","clinical_judgment","A post-operative patient has a hemovac drain with no output for 8 hours.","What would you do about a non-draining surgical drain?","I would assess the drain for clots, kinks, or loss of suction. I would check the wound site for swelling that might indicate fluid accumulation. I would verify the drain is properly compressed to maintain suction. I would document the lack of output and notify the surgeon, as this could indicate drain malfunction or that drainage has resolved. I would not irrigate the drain without a provider order.","Surgical drain troubleshooting and provider notification.","intermediate"),
  q("sq-ex5-13","interview_preparation","scenario_responses","A patient refuses to allow a nursing student to participate in their care.","How would you handle a patient refusing student involvement?","I would respect the patient's decision—they have the right to refuse care from any provider, including students. I would ensure the patient receives the same quality of care and not make them feel guilty. I would find an alternative learning opportunity for the student. I would document the patient's preference in the chart so future shifts are aware.","Respecting patient autonomy regarding student participation.","beginner"),
  q("sq-ex5-14","interview_preparation","scenario_responses","A patient gives you a religious pamphlet and wants to discuss their faith.","How would you respond to a patient sharing their religious beliefs?","I would accept the pamphlet graciously and listen respectfully if the patient wants to share. I would not share my own religious views as this could be inappropriate in the therapeutic relationship. I would offer pastoral care services if they want to discuss their faith more deeply. Spiritual care is an important dimension of holistic nursing, and I would support the patient's spiritual needs.","Respectful engagement with patient's spirituality without imposing personal views.","beginner"),
  q("sq-ex5-15","interview_preparation","scenario_responses","A patient is admitted for a suicide attempt and asks you why they were put on 1:1 observation.","How would you explain safety precautions to a suicidal patient?","I would explain with compassion: 'We have someone staying with you because your safety is our top priority right now. This is not a punishment—it is because we care about you and want to make sure you are safe while you are going through this difficult time.' I would maintain a non-judgmental tone and encourage them to share their feelings. I would document the conversation.","Compassionate explanation of safety measures without shame.","intermediate"),
  q("sq-ex5-16","workplace_scenarios","prioritization","You have a patient who needs a STAT medication, another who needs dressing change, and a third wanting to talk about their anxiety.","How would you prioritize these three needs?","The STAT medication is highest priority as it was ordered urgently for a clinical reason. I would administer that first. The dressing change is next as wound care is time-sensitive. The patient with anxiety is important but can wait briefly—I would acknowledge them: 'I want to give you my full attention. Let me finish two urgent tasks and I will be back in 20 minutes.' I would follow through.","STAT orders first, then clinical tasks, then emotional support with follow-through.","beginner"),
  q("sq-ex5-17","workplace_scenarios","prioritization","Your charge nurse asks you to take a new admission while you are already behind on your current patients.","How would you communicate about workload capacity?","I would be honest and specific: 'I want to take this admission, but I am currently behind on [specific tasks] for my existing patients. I am concerned about patient safety if I take on more right now. Can we discuss either getting help with my current tasks or assigning the admission to someone else?' I would not simply refuse—I would propose solutions.","Transparent workload communication with proposed solutions.","intermediate"),
  q("sq-ex5-18","workplace_scenarios","prioritization","A patient's pain medication is overdue by 30 minutes and they are becoming increasingly agitated.","How would you handle an overdue PRN pain medication?","I would administer the medication as soon as possible while being honest: 'I apologize for the delay. Let me get your pain medication right now.' I would assess their pain level, administer the medication, and follow up in 30 minutes to assess effectiveness. I would reflect on why it was overdue and adjust my workflow to prevent future delays. Timely pain management is a quality indicator.","Immediate action with honest communication about delays.","beginner"),
  q("sq-ex5-19","workplace_scenarios","delegation","You need to delegate patient education to a CNA but education is outside CNA scope.","How would you handle a task that cannot be delegated?","I would recognize that patient education is within the RN scope and cannot be delegated to a CNA. I would keep the education task for myself and delegate other appropriate tasks instead—vital signs, hygiene, ambulation, or stocking supplies. Understanding scope of practice for each team member prevents unsafe delegation and protects patient safety.","Scope of practice awareness prevents inappropriate delegation.","beginner"),
  q("sq-ex5-20","workplace_scenarios","delegation","You are precepting a new orientee and need to balance teaching with efficient patient care.","How would you delegate to a new orientee effectively?","I would assign tasks based on their current competency level and gradually increase complexity. I would provide clear expectations and be available for questions without hovering. I would debrief after complex tasks to reinforce learning. I would balance their learning needs with patient safety—never allowing an orientee to perform tasks they are not ready for unsupervised.","Graduated delegation with learning-focused supervision.","intermediate"),
  q("sq-ex5-21","workplace_scenarios","patient_safety","A patient receiving a narcotic through a PCA pump has family members pressing the button for them.","How would you address family members pressing the PCA button?","I would educate the family: 'The PCA pump is designed so only the patient presses the button. This safety feature prevents overdose—if the patient is too sedated to press the button, their body is telling us they do not need more medication. Please let your loved one manage the button themselves.' I would monitor the patient closely and document the education.","PCA safety education about 'PCA by proxy' dangers.","intermediate"),
  q("sq-ex5-22","workplace_scenarios","patient_safety","A patient's IV has been running for 96 hours without being changed.","How would you address an overdue IV site change?","CDC guidelines and most facility policies recommend changing peripheral IV sites every 72-96 hours to prevent phlebitis and infection. I would change the IV to a new site, assess the old site for signs of phlebitis or infection, and document the site change. I would review why the change was missed and ensure future changes are tracked in the care plan.","Infection prevention through timely IV site rotation.","beginner"),
  q("sq-ex5-23","workplace_scenarios","patient_safety","A confused patient pulls out their NG tube during the night.","How would you manage an accidental NG tube removal?","I would first assess the patient's airway, breathing, and comfort. I would check for signs of aspiration. I would notify the provider about the tube displacement and obtain orders for replacement if needed. I would assess why the patient pulled the tube—confusion, discomfort, or agitation—and implement measures to prevent recurrence such as mittens, sedation assessment, or tube securing methods.","Assessment first, then communication and prevention planning.","intermediate"),
  q("sq-ex5-24","workplace_scenarios","medication_error","You accidentally scan the wrong patient's barcode before administering medication.","How would you recover from a barcode scanning error?","The barcode system should alert me to the mismatch. I would stop immediately, verify I have the correct patient, and rescan. If I had already administered the medication to the wrong patient, I would assess them immediately, notify both patients' providers, document the error, and file an incident report. Barcode scanning errors are exactly the type of mistake the system is designed to catch.","Barcode safety systems as error prevention tools.","beginner"),
  q("sq-ex5-25","workplace_scenarios","medication_error","A patient is prescribed two medications known to have a significant drug interaction.","How would you handle a drug interaction alert?","I would not administer either medication until the interaction is addressed. I would contact the pharmacist for guidance on the interaction severity and clinical significance. I would notify the prescriber: 'I have an interaction alert between these two medications. The pharmacist recommends...' Not all interaction alerts require medication changes, but all require assessment and provider awareness.","Drug interaction alerts require pharmacist consultation and provider notification.","intermediate"),
  q("sq-ex5-26","workplace_scenarios","medication_error","You realize you forgot to flush a peripheral IV before and after administering a medication.","How would you handle a missed IV flush?","I would flush the line now if the patient still has IV access. I would assess the IV site for signs of occlusion or phlebitis. I would document the missed flush and monitor the line for patency. If the medication requires a specific flush protocol (like vancomycin requiring NS flush before and after), I would be extra vigilant about potential complications.","Immediate correction and monitoring for missed procedural steps.","beginner"),
  q("sq-ex5-27","workplace_scenarios","handoff_communication","You are transitioning from days to nights and need to handoff a complex ICU patient.","How would you organize handoff for a critically ill patient?","I would use a systematic approach covering all body systems: neurological status and sedation, respiratory status and ventilator settings, cardiovascular status including drips, renal function and urine output, GI status and nutrition, skin integrity, lines and access, labs pending, and family communication needs. I would highlight changes during my shift and anticipate overnight needs.","Systematic body-systems approach for ICU handoff.","advanced"),
  q("sq-ex5-28","workplace_scenarios","handoff_communication","During handoff, the receiving nurse asks about something you documented but now realize may be inaccurate.","How would you handle discovering a potential documentation error during handoff?","I would be transparent: 'Now that you mention it, I want to verify that finding. Let me check the patient one more time before I leave.' I would reassess, correct my documentation if needed, and thank the receiving nurse for catching it. Handoff is a safety checkpoint, and honest correction is always better than letting an error persist.","Using handoff as a quality checkpoint for documentation accuracy.","beginner"),
  q("sq-ex5-29","workplace_scenarios","difficult_coworkers","A night shift colleague consistently leaves tasks undone for the day shift.","How would you address incomplete handoff tasks from the previous shift?","I would first complete the urgent undone tasks for patient safety. I would document what was incomplete and discuss it with the charge nurse. I would also approach the night shift colleague directly: 'I have noticed some tasks being carried over to day shift. Can we discuss what happened?' There may be legitimate reasons or it may be a pattern that needs management attention.","Complete tasks for safety, then address the pattern.","intermediate"),
  q("sq-ex5-30","workplace_scenarios","difficult_coworkers","A colleague constantly interrupts you while you are charting.","How would you manage interruptions during documentation?","I would set boundaries politely: 'I am in the middle of documenting a critical assessment right now. Can I come find you in about 10 minutes?' If interruptions are chronic, I would find a quieter charting location or use a visual signal that I am focusing. I would not be rude but would be clear that uninterrupted documentation time is necessary for accuracy.","Professional boundary-setting for documentation time.","beginner"),
  q("sq-ex5-31","workplace_scenarios","interdisciplinary_communication","A consultant writes an order that contradicts the primary team's plan without communicating the change.","How would you handle conflicting orders from different medical teams?","I would not execute conflicting orders. I would contact both the consultant and the primary team to reconcile the discrepancy. I would document my communication and ensure a unified plan of care. Conflicting orders are a common safety hazard in hospitals with multiple consulting services, and nursing plays a critical role in catching and resolving them.","Nursing as the safety net for multi-team order conflicts.","intermediate"),
  q("sq-ex5-32","workplace_scenarios","interdisciplinary_communication","You need to communicate with a physician who prefers texting over phone calls.","How would you use secure messaging effectively for clinical communication?","I would use the facility's secure messaging platform (never personal texting) for non-urgent communications. I would be concise and include patient identifiers, the clinical issue, and what I need from them. For urgent situations, I would always call directly. I would document that communication occurred and any orders received through secure messaging. I would never send PHI through unsecured channels.","Appropriate use of secure communication technology.","beginner"),
  q("sq-ex5-33","clinical_transition","first_shift","You make an error in medication preparation that your preceptor catches before administration.","How would you respond to a preceptor catching your error?","I would thank my preceptor sincerely for catching the error and take time to understand what went wrong. I would analyze my thought process to identify where the error originated. I would not become overly emotional or self-critical—this is exactly why I have a preceptor. I would develop a personal checklist to prevent similar errors and share the learning with my cohort if appropriate.","Gratitude for safety catches and constructive error analysis.","beginner"),
  q("sq-ex5-34","clinical_transition","first_shift","Your first patient dies during your orientation period.","How would you cope with your first patient death?","I would allow myself to feel the emotions—grief, sadness, perhaps guilt. I would participate in post-mortem care with respect and dignity. I would debrief with my preceptor and seek support from the chaplain or EAP if needed. I would not pretend to be unaffected. I would also reflect on what I learned about end-of-life care and how I can better support patients and families in the future.","Emotional processing with professional support-seeking.","intermediate"),
  q("sq-ex5-35","clinical_transition","new_nurse_anxiety","You feel underprepared for a specific type of emergency.","How would you address specific clinical knowledge gaps?","I would identify the specific emergency I feel underprepared for and take action: review protocols, attend simulation training, watch educational videos, and ask experienced nurses to walk me through scenarios. I would practice mentally rehearsing my response. Acknowledging gaps is the first step—directed self-education fills them. I would also ensure I know where emergency resources and equipment are located.","Targeted education for identified knowledge gaps.","beginner"),
  q("sq-ex5-36","clinical_transition","new_nurse_anxiety","A patient's condition changes rapidly and you freeze momentarily.","How would you recover from freezing during a clinical emergency?","Freezing momentarily is a normal stress response. I would use the ABC approach to restart my thinking: Airway, Breathing, Circulation. I would call for help—you do not have to manage emergencies alone. I would focus on one task at a time rather than trying to do everything simultaneously. After the event, I would debrief and practice simulation scenarios to build automatic responses.","Using structured frameworks to overcome freeze response.","intermediate"),
  q("sq-ex5-37","clinical_transition","time_management","You are consistently staying 30-60 minutes past your shift to finish charting.","What strategies can reduce end-of-shift overtime?","I would analyze where my time goes during the shift. Common solutions include: charting in real-time rather than batching at end of shift, using templates for repetitive documentation, clustering care activities to reduce trips, delegating appropriate tasks, and setting personal milestones throughout the shift. I would also discuss with my manager whether the workload distribution is appropriate.","Workflow analysis and real-time documentation habits.","beginner"),
  q("sq-ex5-38","clinical_transition","time_management","Multiple patients have PRN medications due and you need to manage them all.","How would you manage multiple PRN medication requests?","I would triage by pain levels and urgency—give the most uncomfortable patient their medication first. I would prepare all PRN medications in order rather than making multiple trips to the medication room. I would reassess each patient after administration to ensure effectiveness. I would document each administration and reassessment promptly to avoid confusion about timing.","Batch PRN management with systematic reassessment.","beginner"),
  q("sq-ex5-39","clinical_transition","documentation_challenges","You need to document a lengthy patient and family conversation about goals of care.","How would you document a goals of care discussion?","I would document: who was present, key topics discussed, the patient's and family's expressed wishes and concerns, decisions made, plans agreed upon, and next steps. I would use direct quotes for critical statements. I would note any emotional responses and support provided. I would update the advance directive section of the chart accordingly and communicate decisions to the care team.","Comprehensive documentation of critical care planning conversations.","intermediate"),
  q("sq-ex5-40","clinical_transition","documentation_challenges","Your facility is transitioning to a new EHR system during your orientation.","How would you manage an EHR transition as a new nurse?","I would attend all training sessions, practice in the sandbox environment, and create personal quick-reference guides. I would be patient with myself and the system. I would report any issues or workarounds I discover. I would use the super-users and help desk as resources. I would maintain safety vigilance during the transition, as system changes increase error risk.","Proactive EHR transition learning with safety awareness.","beginner"),
  q("sq-ex5-41","clinical_transition","critical_thinking_drills","A patient's CRP is elevated at 85 mg/L.","What does a highly elevated CRP indicate?","CRP (C-reactive protein) at 85 is significantly elevated (normal <10 mg/L) and indicates a substantial inflammatory process—commonly infection, tissue injury, or autoimmune flare. I would assess for infection sources, check other inflammatory markers like ESR and procalcitonin, review recent procedures or injuries, and correlate with clinical symptoms. I would notify the provider and monitor the trend.","CRP as a nonspecific but significant inflammation marker.","intermediate"),
  q("sq-ex5-42","clinical_transition","critical_thinking_drills","A patient with a new chest tube has continuous bubbling in the water seal chamber.","What does continuous bubbling in a chest tube water seal indicate?","Continuous bubbling in the water seal chamber indicates an air leak—either from the patient's pleural space (expected after pneumothorax) or from a system leak. I would check all connections for tightness, look for cracks in tubing, and briefly clamp the tube close to the patient to differentiate between patient air leak and system air leak. If the bubbling stops with clamping, the leak is from the patient. I would notify the provider.","Chest tube troubleshooting for air leak assessment.","advanced"),
  q("sq-ex5-43","clinical_transition","critical_thinking_drills","A post-operative patient develops hiccups that will not stop.","What could persistent post-operative hiccups indicate?","Persistent hiccups after surgery can indicate diaphragmatic irritation from abdominal distension, gastric distention, subdiaphragmatic abscess, or phrenic nerve irritation. In some cases, they may indicate metabolic derangements like uremia or electrolyte imbalances. I would assess the abdomen, check recent labs, try conservative measures (holding breath, drinking water), and notify the provider if hiccups persist beyond a few hours.","Recognizing hiccups as a potential sign of post-operative complications.","intermediate"),
  q("sq-ex5-44","professional_development","professional_boundaries","A patient's family invites you to a celebration after discharge.","How would you respond to a social invitation from a patient's family?","I would decline warmly: 'I am so happy for the recovery, and your invitation is very kind. However, I need to maintain my professional boundaries. I wish your family all the best.' I would not attend social events with current or recent patients or their families, as this crosses professional boundaries and could create complications if they are readmitted.","Consistent professional boundary maintenance with warmth.","beginner"),
  q("sq-ex5-45","professional_development","ethical_dilemmas","You discover that a patient has been stockpiling their PRN medications instead of taking them.","How would you handle discovering a patient hoarding medications?","I would assess the patient's intent—are they saving medications for pain management at home, self-harm, or other reasons? I would secure the hoarded medications immediately. I would notify the provider and discuss the findings without accusation: 'I found several untaken medications. I want to understand why so we can better address your needs.' If self-harm is suspected, I would implement appropriate safety measures.","Intent assessment before determining safety interventions.","intermediate"),
  q("sq-ex5-46","professional_development","ethical_dilemmas","A pharmaceutical representative offers your unit expensive gifts.","How would you handle pharmaceutical company gifts?","I would follow facility policy, which typically prohibits accepting gifts above a minimal value from pharmaceutical companies. I would decline the gift professionally and report the offer to my manager. Pharmaceutical gifts can create unconscious bias in prescribing and product selection. Evidence-based practice should guide clinical decisions, not industry influence.","Maintaining independence from pharmaceutical industry influence.","intermediate"),
  q("sq-ex5-47","professional_development","workplace_bullying","A nurse manager plays favorites and gives preferential treatment to certain nurses.","How would you address favoritism by management?","I would document specific examples of preferential treatment with dates and details. I would request a private meeting with my manager to discuss my concerns about equitable treatment. If the favoritism affects patient care assignments, professional development opportunities, or scheduling fairness, I would escalate to HR or the next level of management. I would focus on the impact on patient care and team morale rather than personal grievance.","Documentation-based approach to addressing management favoritism.","intermediate"),
  q("sq-ex5-48","professional_development","advocacy","A patient is being sent home with a complex wound care regimen but cannot afford the supplies.","How would you ensure wound care continuity after discharge?","I would contact social work about financial assistance programs, reach out to wound care supply companies about patient assistance programs, teach the patient about affordable alternative supplies, coordinate with home health for supply provision, and ensure they have enough supplies to last until the first outpatient appointment. I would not discharge without a clear plan for wound care supply access.","Multi-resource approach to ensuring supply access.","intermediate"),
  q("sq-ex5-49","professional_development","advocacy","A patient with a mental health condition is being treated differently by the medical team.","How would you address stigma-based care differences?","I would advocate directly: 'I have noticed that this patient's physical complaints are being attributed to their mental health diagnosis without thorough workup. Can we ensure they receive the same diagnostic evaluation as any other patient with these symptoms?' Mental health stigma in healthcare can lead to missed diagnoses and inadequate treatment. I would document my advocacy.","Advocating against mental health stigma in clinical care.","advanced"),
  q("sq-ex5-50","professional_development","patient_communication","A patient is non-compliant with their diet and you need to discuss it without being judgmental.","How would you address dietary non-compliance compassionately?","I would use motivational interviewing: 'I have noticed some challenges with your prescribed diet. Can you tell me what has been difficult about following it?' I would listen for barriers—financial, cultural, practical—and work with them to find realistic solutions. I would avoid the word 'non-compliant' and instead focus on understanding their perspective and creating a workable plan together.","Motivational interviewing for behavior change without judgment.","intermediate"),
  q("sq-ex5-51","career_navigation","job_offer_negotiation","You receive an offer but the benefits package seems below average.","How would you negotiate a better benefits package?","I would research standard benefits for the region and position. I would say: 'I am excited about this opportunity. I have compared the benefits package to regional standards and noticed that the health insurance contribution and PTO allocation are below average. Is there flexibility to adjust these components? Strong benefits are an important factor in my decision and contribute to long-term retention.'","Market-based benefits negotiation with retention framing.","intermediate"),
  q("sq-ex5-52","career_navigation","probation_period","Your preceptor goes on leave and you are assigned to complete probation with a temporary preceptor.","How would you adapt to a mid-probation preceptor change?","I would share my orientation progress with the new preceptor: completed competencies, current learning goals, and areas where I still need support. I would ask about their teaching style and preferences. I would maintain a log of my competency development to ensure continuity. I would also keep my nurse educator informed about the transition to ensure nothing falls through the cracks.","Proactive communication for preceptor transition continuity.","beginner"),
  q("sq-ex5-53","career_navigation","performance_evaluation","You want to discuss a promotion to a specialty unit during your evaluation.","How would you advocate for a specialty transfer at evaluation time?","I would present a clear case: 'I have consistently met or exceeded my performance goals, completed [relevant certifications], and expressed interest in [specialty]. I believe I am ready for the challenge and would like to discuss what steps are needed for a transfer.' I would show that I have already taken initiative to prepare for the specialty through education and clinical experience.","Initiative-demonstrating transfer request with preparation evidence.","intermediate"),
  q("sq-ex5-54","career_navigation","career_advancement","You are considering per diem work in addition to your full-time position.","How would you evaluate taking on per diem work?","I would consider: my facility's policy on outside employment, the impact on my rest and patient safety, whether per diem experience would enhance my skills, the financial benefit versus burnout risk, and whether it conflicts with my primary position's scheduling. Per diem work can provide diverse experience and extra income, but nurse fatigue is a patient safety concern.","Balanced assessment of supplemental work opportunities.","beginner"),
  q("sq-ex5-55","career_navigation","career_advancement","You want to develop your public speaking skills for professional advancement.","How would you build confidence in professional speaking?","I would start small by volunteering to lead team huddles or present at unit meetings. I would practice with a small, supportive audience before larger groups. I would prepare thoroughly and use visual aids. I would join a professional development group like Toastmasters. I would watch skilled nursing presenters and study their techniques. Each speaking opportunity builds confidence for the next.","Progressive public speaking development.","beginner"),
  q("sq-ex5-56","interview_preparation","clinical_judgment","A patient on a ventilator has a sudden increase in peak inspiratory pressure.","What does increased PIP on a ventilator indicate?","Increased peak inspiratory pressure suggests increased airway resistance or decreased lung compliance. Causes include mucus plugging, bronchospasm, pneumothorax, biting the ET tube, kinked tubing, or patient-ventilator dyssynchrony. I would suction the patient, check tubing for kinks, assess breath sounds for pneumothorax or bronchospasm, and check patient positioning. I would notify respiratory therapy and the provider.","Systematic troubleshooting of ventilator alarms.","advanced"),
  q("sq-ex5-57","interview_preparation","clinical_judgment","A patient develops sudden onset of facial drooping, arm weakness, and slurred speech.","What emergency do you recognize and what is the priority?","This is a stroke alert—the patient is showing classic signs of a cerebrovascular accident. Time is critical. I would call a code stroke, note the exact time symptoms began (last known well time), perform a rapid neurological assessment, check blood glucose, and prepare for emergent CT scan. For ischemic stroke, the tPA window is typically 4.5 hours from symptom onset. Every minute of delay means more brain tissue loss.","Stroke recognition with time-critical response.","intermediate"),
  q("sq-ex5-58","workplace_scenarios","prioritization","You are managing care for patients on different floors due to staffing.","How would you manage patients on multiple units?","I would organize by urgency and geography, making sure to see the most acute patients first regardless of floor. I would establish communication with the charge nurse on each floor and delegate tasks to unit-based staff. I would carry all patients' information with me and set a schedule for rounding. I would communicate my location and availability to both units at all times.","Multi-unit organization with communication and delegation.","advanced"),
  q("sq-ex5-59","workplace_scenarios","patient_safety","A patient with an allergy to eggs is scheduled to receive a flu vaccine.","What precaution is needed for egg allergy and vaccines?","Current CDC guidelines state that people with egg allergies can receive the flu vaccine with appropriate precautions. For patients with a history of severe allergic reaction to eggs, the vaccine should be administered in a medical setting by a healthcare provider who can recognize and manage allergic reactions. I would verify the specific vaccine formulation and have emergency medications available.","Current evidence-based vaccine safety knowledge.","intermediate"),
  q("sq-ex5-60","clinical_transition","critical_thinking_drills","A patient's platelet count drops from 200,000 to 50,000 while on heparin.","What does this platelet drop suggest?","A significant platelet drop (more than 50% from baseline) while on heparin suggests heparin-induced thrombocytopenia (HIT)—a serious, potentially fatal condition that paradoxically causes clotting rather than bleeding. I would stop all heparin products immediately (including heparin flushes), notify the provider, send a HIT antibody test, and anticipate alternative anticoagulation. HIT requires immediate intervention.","HIT recognition with immediate heparin cessation.","advanced"),
  q("sq-ex5-61","professional_development","ethical_dilemmas","You learn that a colleague has been drinking alcohol before coming to work.","How would you handle suspicion that a colleague is impaired at work?","I would observe for specific signs of impairment: alcohol odor, slurred speech, unsteady gait, poor judgment, or erratic behavior. I would report my concerns to the charge nurse or manager immediately—this is a patient safety emergency, not gossip. I would document my specific observations. If the colleague is providing direct patient care, their patients need to be reassigned immediately while the situation is assessed.","Immediate reporting of impairment for patient safety.","advanced"),
  q("sq-ex5-62","professional_development","patient_communication","A patient does not understand discharge instructions despite your teaching.","How would you modify your teaching approach for a patient who is not understanding?","I would step back and assess the barrier: language, cognitive ability, health literacy, hearing, or overwhelm. I would try a different approach: visual aids instead of verbal, simplified instructions, smaller amounts of information at a time, or involving a family member. I would use the teach-back method: 'Show me how you would take your medications at home.' If necessary, I would arrange for home health teaching reinforcement.","Adaptive teaching with barrier assessment and alternative methods.","beginner"),
  q("sq-ex5-63","career_navigation","performance_evaluation","Your manager asks you to evaluate yourself as part of your annual review.","How would you write an effective self-evaluation?","I would be honest and balanced—acknowledging accomplishments with specific examples while identifying genuine areas for growth. I would include: patient satisfaction feedback, competencies achieved, committee participation, continuing education completed, quality metrics I contributed to, and goals I achieved. I would avoid being either overly modest or boastful. A thoughtful self-evaluation demonstrates self-awareness and professionalism.","Balanced self-evaluation with specific evidence.","beginner"),
  q("sq-ex5-64","career_navigation","probation_period","You made a medication error during your probation period.","How would you handle a medication error during probation?","I would report it immediately following incident reporting procedures—transparency is essential, especially during probation. I would assess the patient, notify the provider, and document everything. I would take full responsibility and develop a prevention plan. Making an error during probation is not automatically career-ending—how you handle it demonstrates your character and commitment to patient safety.","Transparent error reporting demonstrates integrity regardless of timing.","intermediate"),
  q("sq-ex5-65","interview_preparation","behavioral","Describe a time when your attention to cultural differences improved patient care.","How has cultural awareness improved your nursing practice?","I cared for a Native American patient who refused blood draws. Rather than labeling them as non-compliant, I asked about their cultural beliefs and learned that blood holds spiritual significance in their tradition. I worked with the medical team to minimize unnecessary blood draws and combine labs when possible. This respectful approach improved the patient's trust and cooperation with their overall treatment plan.","Cultural inquiry leading to care modification and improved outcomes.","intermediate"),
  q("sq-ex5-66","workplace_scenarios","medication_error","A patient is prescribed a medication they are already taking at home but at a different dose.","How would you handle a dosing discrepancy between home and hospital medications?","I would not administer the medication until the discrepancy is clarified. I would check the medication reconciliation, contact the prescriber to verify the intended dose, and confirm whether the dose change was intentional or an error. I would document the clarification. Unintentional dose changes at admission and discharge are among the most common medication errors.","Medication reconciliation as a critical safety process.","beginner"),
  q("sq-ex5-67","clinical_transition","time_management","You need to prioritize between completing a required education module and helping on the floor.","How would you balance mandatory education with patient care demands?","Patient care always takes priority over education modules. I would communicate with my manager about needing protected time for the module and schedule it during a lower-acuity period. I would complete what I can during downtime and ask for coverage if I need uninterrupted time. I would not rush through required education just to check a box—the content is meant to improve patient safety.","Patient care priority with planned education time.","beginner"),
  q("sq-ex5-68","professional_development","workplace_bullying","You are asked to work extra shifts repeatedly while others are not asked.","How would you address being disproportionately asked to work overtime?","I would track the requests objectively and compare with how often others are asked. I would discuss it with my manager: 'I have been asked to work extra shifts 8 times this month while some colleagues have not been asked at all. I want to help the team, but I also need equitable treatment and time for self-care.' I would set boundaries while showing willingness to do my fair share.","Objective documentation of inequitable overtime distribution.","intermediate"),
  q("sq-ex5-69","interview_preparation","clinical_judgment","A patient on warfarin develops spontaneous bruising and has an INR of 8.","What would you do for a critically elevated INR?","An INR of 8 is dangerously supratherapeutic and poses immediate hemorrhage risk. I would hold warfarin, assess for active bleeding (check stool, urine, neurological status), notify the provider immediately, and anticipate orders for vitamin K (oral or IV depending on bleeding status) and possibly fresh frozen plasma or prothrombin complex concentrate for active bleeding. I would implement fall precautions and avoid invasive procedures.","Critical anticoagulation reversal management.","advanced"),
  q("sq-ex5-70","workplace_scenarios","interdisciplinary_communication","You notice that the physical therapy progress notes suggest the patient is more mobile than what you observe.","How would you address discrepancy between nursing and PT assessments?","I would communicate with the PT directly: 'I noticed your notes indicate the patient ambulated 200 feet independently, but when I assist them, they seem unsteady and need support. Can we assess together to make sure we are seeing the same thing?' Patients may perform differently at different times of day or with different providers. A joint assessment resolves the discrepancy and ensures safe discharge planning.","Collaborative reassessment to resolve clinical discrepancies.","intermediate"),
  q("sq-ex5-71","clinical_transition","critical_thinking_drills","A patient's BUN-to-creatinine ratio is 30:1.","What does an elevated BUN-to-creatinine ratio suggest?","A BUN-to-creatinine ratio above 20:1 suggests prerenal azotemia—meaning the kidneys are not getting enough blood flow. Common causes include dehydration, heart failure, hemorrhage, or sepsis. I would assess fluid status, check vital signs for hypovolemia or heart failure signs, review I&O records, and notify the provider. I would anticipate a fluid challenge unless contraindicated by heart failure.","Prerenal azotemia identification through lab ratio analysis.","intermediate"),
  q("sq-ex5-72","professional_development","advocacy","A patient is being denied a necessary medication by their insurance mid-hospitalization.","How would you advocate for insurance coverage of essential medication?","I would involve the case manager and social worker immediately. I would support the physician in providing clinical justification for the medication. I would explore pharmacy assistance programs, manufacturer patient assistance, or alternative medications that are covered. I would not let the patient go without necessary treatment due to insurance bureaucracy—there are always alternative pathways to explore.","Multi-resource advocacy for insurance barrier navigation.","intermediate"),
  q("sq-ex5-73","interview_preparation","scenario_responses","A patient asks if they can record your conversation on their phone.","How would you handle a patient wanting to record you?","I would check my facility's recording policy. Many facilities allow patients to record for their own educational purposes. I would say, 'I want to make sure we follow our facility policy on recordings. Let me check, and if it is permitted, I am happy for you to record so you can review the information later.' I would not be defensive—recording can actually help patients remember discharge instructions.","Policy-compliant response without defensiveness.","beginner"),
  q("sq-ex5-74","workplace_scenarios","patient_safety","A power outage occurs on your unit during the night shift.","How would you manage patient safety during a power outage?","I would immediately check that the backup generator activates for life-support equipment and emergency lighting. I would round on all patients, prioritizing those on ventilators, IV drips, and cardiac monitoring. I would use flashlights for assessments, manually monitor patients whose equipment has lost power, and ensure all staff know the emergency procedures. I would communicate with the charge nurse and facilities.","Emergency response to infrastructure failure.","advanced"),
  q("sq-ex5-75","career_navigation","career_advancement","You are considering moving into case management nursing.","How would you prepare for a transition to case management?","I would develop skills in care coordination, utilization review, and discharge planning by actively participating in these activities at the bedside. I would learn about insurance processes, Medicare/Medicaid guidelines, and community resources. I would pursue case management certification (CCM) and network with current case managers. Understanding the business side of healthcare complements clinical knowledge.","Skill development for case management transition.","intermediate"),
  q("sq-ex5-76","interview_preparation","behavioral","Tell me about your commitment to lifelong learning.","How do you approach continuous professional development?","I maintain a personal learning plan that includes specialty reading, continuing education courses, conference attendance, and clinical skill practice. I subscribe to nursing journals and participate in evidence-based practice discussions. I view every patient interaction as a learning opportunity. I believe that the day I stop learning is the day I stop being an effective nurse.","Specific learning habits demonstrating ongoing commitment.","beginner"),
  q("sq-ex5-77","workplace_scenarios","handoff_communication","You need to give report but the receiving nurse says they already looked at the chart.","How would you handle a nurse who does not want verbal report?","I would emphasize the importance of verbal communication: 'I appreciate that you reviewed the chart. I still want to share a few things that may not be in the notes yet, including changes in the last hour and my clinical impressions. Can I give you a brief focused report?' Chart review alone misses nuances that verbal communication captures.","Advocating for verbal communication despite chart review.","beginner"),
  q("sq-ex5-78","clinical_transition","new_nurse_anxiety","You feel like every patient situation is an emergency and you cannot distinguish urgency levels.","How would you develop clinical prioritization skills?","I would practice using urgency assessment frameworks: Is this life-threatening? Does it need intervention within minutes, hours, or can it wait? I would discuss prioritization decisions with my preceptor after each shift. I would study triage categories and clinical deterioration signs. Over time, pattern recognition develops and distinguishing urgency becomes more automatic.","Framework-based prioritization development.","beginner"),
  q("sq-ex5-79","professional_development","ethical_dilemmas","A patient tells you they plan to stop taking all medications when they get home.","How would you respond to a patient planning to discontinue medications?","I would explore their reasons: cost, side effects, feeling better, health beliefs, or distrust of medications. I would educate about the specific risks of stopping each medication abruptly. I would involve the pharmacist for a medication review and the physician for possible simplification. Ultimately, I would document the education provided, the patient's decision, and that they were informed of the risks.","Thorough education while respecting patient autonomy.","intermediate"),
  q("sq-ex5-80","career_navigation","job_offer_negotiation","You are deciding between a teaching hospital and a community hospital for your first job.","How would you compare teaching versus community hospital for first position?","Teaching hospitals offer broader exposure to complex cases, access to latest research, and strong educational resources but may have busier environments with multiple learners. Community hospitals often have closer-knit teams, broader scope of nursing practice, and potentially lower nurse-to-patient ratios. I would consider which environment best supports my learning style and career goals.","Thoughtful comparison of institutional types for career fit.","beginner"),
  q("sq-ex5-81","interview_preparation","clinical_judgment","A patient with pancreatitis has increasing abdominal pain and a lipase level of 5000 U/L.","What does a markedly elevated lipase indicate?","A lipase of 5000 (normal <60 U/L) with increasing abdominal pain indicates severe acute pancreatitis. I would ensure the patient is NPO, aggressively manage pain, maintain IV fluid resuscitation, monitor for signs of organ failure (respiratory, renal, hemodynamic), and assess for complications like pancreatic necrosis or pseudocyst. I would anticipate possible ICU transfer for severe cases and monitor calcium and glucose levels.","Severe pancreatitis management priorities.","advanced"),
  q("sq-ex5-82","workplace_scenarios","delegation","You need to assign tasks during a rapid response situation.","How would you delegate effectively during an emergency?","I would assign tasks clearly and specifically using names: 'Sarah, get the vital signs. Mike, bring the crash cart. Lisa, call the attending physician.' I would use closed-loop communication: 'Did you understand what I need?' I would delegate based on scope and skill level. I would maintain situational awareness and reassign tasks as the situation evolves. Clear, direct delegation saves lives in emergencies.","Name-specific, closed-loop delegation during emergencies.","advanced"),
  q("sq-ex5-83","clinical_transition","documentation_challenges","You witness an incident but are not the assigned nurse for that patient.","How would you document a witnessed event for another nurse's patient?","I would document what I personally observed as a witness note or addendum in the patient's chart. I would include the time, what I saw, what I did, and who I notified. I would also write an incident report if appropriate. I would communicate with the assigned nurse to ensure they are aware and have the information they need. Witnessing an event creates a documentation responsibility.","Witness documentation obligations and communication.","intermediate"),
  q("sq-ex5-84","professional_development","patient_communication","A patient with depression is refusing to participate in their recovery.","How would you motivate a depressed patient to engage in care?","I would start with empathy and validation: 'I understand you are going through a really difficult time.' I would set small, achievable goals rather than overwhelming expectations. I would celebrate small wins. I would consult psychiatry for medication management and request therapeutic activities. I would not push too hard but would maintain consistent, compassionate encouragement. Depression affects motivation, and patience is key.","Small goals, empathy, and interdisciplinary support for depression.","intermediate"),
  q("sq-ex5-85","career_navigation","performance_evaluation","You disagree with a specific competency rating on your evaluation.","How would you challenge a specific evaluation rating?","I would prepare documentation supporting my position—specific examples, patient outcomes, and feedback I have received. I would request a meeting: 'I noticed my rating for [competency] was lower than expected. I would like to discuss the specific criteria used and share some examples I believe demonstrate a higher level of performance.' I would listen to my manager's perspective and work toward mutual understanding.","Evidence-based evaluation discussion.","intermediate"),
  q("sq-ex5-86","interview_preparation","star_examples","Tell me about a time you anticipated a patient's needs before they asked.","Describe how you use anticipatory nursing care.","I noticed that my post-operative patient's dressing was dry but they were guarding their incision site. Before they mentioned pain, I assessed their last pain medication timing, offered a dose proactively, repositioned them for comfort, and checked the surgical site. The patient said, 'I was just about to press the call bell for pain.' Anticipating needs shows attentiveness and prevents suffering.","Proactive assessment and intervention before patient request.","beginner"),
  q("sq-ex5-87","workplace_scenarios","patient_safety","You notice that the sharps container in your patient's room is overfull.","How would you address an overfull sharps container?","I would not attempt to push sharps into an overfull container—this is a needlestick injury risk. I would replace the container immediately with a new one and properly dispose of the full container. I would report the overfull container issue to housekeeping and charge nurse. I would ensure all staff know not to overfill sharps containers and that replacement containers are readily accessible.","Immediate replacement and needlestick injury prevention.","beginner"),
  q("sq-ex5-88","clinical_transition","critical_thinking_drills","A patient's PT/INR results are delayed and they are due for their evening warfarin dose.","Would you give warfarin without current INR results?","I would hold the warfarin until INR results are available. Administering warfarin without knowing the current INR could result in a supratherapeutic level and dangerous bleeding. I would contact the lab about the delay, notify the provider about the situation, and document my clinical reasoning for holding the dose. Patient safety always takes priority over medication schedules.","Holding anticoagulation without monitoring results is appropriate clinical judgment.","intermediate"),
  q("sq-ex5-89","professional_development","advocacy","A patient with chronic pain is being labeled as drug-seeking by the team.","How would you advocate for a patient labeled as drug-seeking?","I would challenge the stigmatizing label by presenting the patient's pain objectively: 'I have assessed the patient and they report 8/10 pain with observable signs of discomfort. Can we develop a comprehensive pain management plan rather than focusing on the label?' I would advocate for a pain management consult. The term 'drug-seeking' is stigmatizing and can lead to undertreated pain.","Advocating against stigmatizing language in clinical care.","advanced"),
  q("sq-ex5-90","career_navigation","career_advancement","You are interested in forensic nursing.","How would you explore a career in forensic nursing?","I would research forensic nursing roles: sexual assault nurse examiner (SANE), death investigator, correctional nurse, or legal nurse consultant. I would pursue SANE certification if interested in evidence collection. I would take forensic nursing courses and network with forensic nurses. I would volunteer with victim advocacy organizations. Clinical experience in emergency nursing provides a strong foundation for forensic nursing.","Exploring niche specialties through targeted education and networking.","intermediate"),
  q("sq-ex5-91","interview_preparation","behavioral","Tell me about your experience with quality metrics.","How do you contribute to quality measurement?","I actively participate in quality metrics by ensuring accurate documentation that supports data collection, following evidence-based protocols that drive quality outcomes, and participating in unit quality meetings where we review our performance data. I understand that quality metrics like HCAHPS scores, fall rates, and infection rates reflect the care we provide and drive continuous improvement.","Quality metrics awareness and active participation.","beginner"),
  q("sq-ex5-92","workplace_scenarios","difficult_coworkers","A colleague is consistently negative during report and makes the shift transition stressful.","How would you handle negativity during shift change?","I would keep my handoff focused and professional regardless of the other nurse's attitude. I would not engage with negativity or gossip during report. I would redirect: 'Let me focus on the clinical priorities for these patients.' If the negativity is persistent and affecting team morale, I would discuss it with the charge nurse. I would protect my own mental energy during shift transitions.","Professional redirection during negative interactions.","beginner"),
  q("sq-ex5-93","clinical_transition","first_shift","You are asked to perform a task you have only done in simulation, never on a real patient.","How would you handle performing a skill for the first time on a real patient?","I would be transparent with my preceptor: 'I have practiced this in simulation but this will be my first time on a patient. Can you supervise me?' I would review the procedure quickly, gather all supplies, explain to the patient that I will be performing the procedure with supervision, and proceed carefully with my preceptor guiding me. Everyone has a first time with every clinical skill.","Transparent first-time disclosure with supervised performance.","beginner"),
  q("sq-ex5-94","professional_development","ethical_dilemmas","A family insists on aggressive treatment for a patient who clearly expressed wishes for comfort care only.","How would you navigate family demands that conflict with patient's advance directive?","I would review the advance directive with the family, involve the ethics committee if needed, and support the patient's documented wishes. I would explain: 'I understand your love for your family member. However, they made this decision when they had capacity, and our obligation is to honor their wishes.' I would involve palliative care and social work for family support. The patient's autonomy must be respected.","Supporting advance directives against family pressure.","advanced"),
  q("sq-ex5-95","career_navigation","probation_period","You have completed your probation successfully and want to set new goals.","How would you transition from probation to independent practice?","I would celebrate the milestone while recognizing that learning continues. I would set professional development goals for the next year: pursuing certification, taking charge assignments, precepting students, and joining a unit committee. I would maintain the mentoring relationships I built during orientation. I would continue to ask questions and seek feedback—graduating from probation does not mean I have nothing left to learn.","Growth-oriented transition from probation to independence.","beginner"),
  q("sq-ex5-96","interview_preparation","clinical_judgment","A patient with a history of seizures has not received their antiepileptic medication for 24 hours due to NPO status.","What is the risk and what should you do?","Missing 24 hours of antiepileptic medication significantly increases seizure risk. I would immediately notify the provider about the missed doses and advocate for IV or alternative formulation of the medication. I would implement seizure precautions: padded side rails, suction at bedside, oxygen available, bed in lowest position. I would never allow a patient to miss seizure medications without provider awareness.","Critical medication gap identification with seizure precaution implementation.","intermediate"),
  q("sq-ex5-97","workplace_scenarios","patient_safety","A patient with a known penicillin allergy has cephalosporin ordered.","What cross-reactivity concern exists and how would you proceed?","Penicillin and cephalosporin antibiotics share structural similarities, and there is a small (1-2%) cross-reactivity risk. I would verify the specific nature of the penicillin allergy—was it a true allergy (anaphylaxis, hives) or an intolerance (GI upset)? I would discuss the risk-benefit with the provider and pharmacist. For severe penicillin allergies, alternative antibiotics should be considered. I would have emergency medications available if the cephalosporin is given.","Cross-reactivity assessment based on allergy severity.","intermediate"),
  q("sq-ex5-98","clinical_transition","critical_thinking_drills","A patient's liver function tests are significantly elevated: AST 500, ALT 600.","What do markedly elevated liver enzymes indicate?","AST and ALT levels this high suggest significant hepatocellular injury. Causes include viral hepatitis, drug-induced liver injury (acetaminophen toxicity is common), ischemic hepatitis, or acute biliary obstruction. I would review the patient's medication list (especially acetaminophen use), assess for jaundice and right upper quadrant pain, check coagulation studies and albumin, and notify the provider for further workup.","Liver enzyme interpretation with differential diagnosis consideration.","advanced"),
  q("sq-ex5-99","professional_development","patient_communication","A patient has a hearing aid but it is not working and you need to communicate urgently.","How would you communicate urgently with a patient whose hearing aid is malfunctioning?","I would face the patient directly, speak clearly at a moderate pace (not shouting), use written notes for critical information, use simple gestures to reinforce key points, and contact the family to bring a replacement hearing aid. For truly urgent medical information, I would write key points in large, clear letters. I would also troubleshoot the hearing aid—check batteries and clean contacts.","Multi-modal urgent communication with hearing impairment.","beginner"),
  q("sq-ex5-100","career_navigation","career_advancement","You want to develop your research skills but do not have a graduate degree.","How can you participate in nursing research without a graduate degree?","I would volunteer as a data collector for active research studies, participate in evidence-based practice projects, conduct literature reviews for clinical questions, and present findings at unit meetings. I would take research methodology courses and join my hospital's nursing research council. Many BSN-prepared nurses contribute meaningfully to research—a graduate degree enables independent research but is not required for participation.","Research participation pathways for BSN-prepared nurses.","intermediate"),
];
